<?php
namespace Tests\Unit\Domain\Shops;
use App\Domain\Shops\ShopPurchaseRate;use App\Domain\Shops\ShopSalePricingService;use InvalidArgumentException;use PHPUnit\Framework\TestCase;
final class ShopSalePricingServiceTest extends TestCase{public function test_it_calculates_unit_and_total_using_integer_basis_points(){$result=(new ShopSalePricingService())->calculate(101,7500,3);$this->assertSame(75,$result->unitGold());$this->assertSame(3,$result->quantity());$this->assertSame(225,$result->totalGold());}public function test_it_handles_large_values_without_multiplying_before_division(){$result=(new ShopSalePricingService())->calculate(PHP_INT_MAX,1,1);$this->assertSame(intdiv(PHP_INT_MAX,10000),$result->unitGold());}public function test_it_rejects_invalid_values_zero_unit_and_overflow(){$service=new ShopSalePricingService();foreach([[0,10000,1],[1,0,1],[1,10001,1],[1,1,1],[PHP_INT_MAX,10000,2]]as$args){try{$service->calculate($args[0],$args[1],$args[2]);$this->fail('Invalid pricing input was accepted.');}catch(InvalidArgumentException $e){$this->assertNotSame('',$e->getMessage());}}}public function test_percentage_conversion_is_string_based_and_exact(){$rates=new ShopPurchaseRate();$this->assertSame(1,$rates->toBasisPoints('0.01'));$this->assertSame(7525,$rates->toBasisPoints('75.25'));$this->assertSame(10000,$rates->toBasisPoints('100'));$this->assertSame('75.25',$rates->toPercentage(7525));$this->expectException(InvalidArgumentException::class);$rates->toBasisPoints('100.01');}}
